import React, { useState, useEffect } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Sphere, MeshDistortMaterial, Float } from '@react-three/drei';

// --- 3D DIGITAL TWIN COMPONENT ---
const PatientModel = ({ peakValue }) => {
  const isDanger = peakValue > 10; 

  return (
    <Float speed={2} rotationIntensity={0.5} floatIntensity={0.5}>
      <Sphere args={[1, 100, 100]} scale={1.4}>
        <MeshDistortMaterial
          color={isDanger ? "#ff2d2d" : "#00d2ff"}
          speed={isDanger ? 10 : 2}
          distort={isDanger ? 0.6 : 0.3}
          roughness={0.2}
          metalness={0.8}
        />
      </Sphere>
    </Float>
  );
};

// --- MAIN DASHBOARD ---
export default function App() {
  const [weight, setWeight] = useState(70);
  const [genFactor, setGenFactor] = useState(1.0);
  const [data, setData] = useState({ levels: [], peak_value: 0 });

  const fetchData = async () => {
    try {
      const res = await fetch(`http://127.0.0.1:8000/simulate?weight=${weight}&gen_factor=${genFactor}`);
      const result = await res.json();
      setData({
        levels: result.levels,
        peak_value: Math.max(...result.levels)
      });
    } catch (err) {
      console.error("Backend not running? Make sure uvicorn is active on port 8000");
    }
  };

  useEffect(() => { fetchData(); }, [weight, genFactor]);

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#0a0a0c', color: 'white', fontFamily: 'sans-serif' }}>
      
      {/* SIDEBAR CONTROLS */}
      <div style={{ width: '350px', padding: '40px', borderRight: '1px solid #333', background: '#111' }}>
        <h2 style={{ color: '#00d2ff', marginBottom: '10px' }}>Medi-Twin Engine</h2>
        <p style={{ fontSize: '12px', color: '#888', marginBottom: '30px' }}>Precision Pharmacology Simulation</p>

        <div style={{ marginBottom: '25px' }}>
          <label style={{ display: 'block', marginBottom: '10px' }}>Patient Weight: <b>{weight} kg</b></label>
          <input 
            type="range" 
            min="40" 
            max="150" 
            value={weight} 
            onChange={(e) => setWeight(e.target.value)} 
            style={{ width: '100%' }} 
          />
        </div>

        <div style={{ marginBottom: '40px' }}>
          <label style={{ display: 'block', marginBottom: '10px' }}>Genetic Factor: <b>{genFactor}x</b></label>
          <input 
            type="range" 
            min="0.5" 
            max="2.5" 
            step="0.1" 
            value={genFactor} 
            onChange={(e) => setGenFactor(e.target.value)} 
            style={{ width: '100%' }} 
          />
        </div>

        {data.peak_value > 0.12 && (
          <div style={{ padding: '15px', background: '#441111', border: '1px solid #ff2d2d', borderRadius: '8px' }}>
            <strong style={{ color: '#ff2d2d' }}>⚠️ TOXICITY ALERT</strong>
            <p style={{ fontSize: '12px', marginTop: '5px' }}>Levels exceed safe clinical thresholds.</p>
          </div>
        )}
      </div>

      {/* 3D VISUAL AREA */}
      <div style={{ flex: 1, position: 'relative' }}>
        <Canvas camera={{ position: [0, 0, 4] }}>
          <ambientLight intensity={0.5} />
          <pointLight position={[10, 10, 10]} />
          <PatientModel peakValue={data.peak_value} />
          <OrbitControls enableZoom={false} />
        </Canvas>
        
        <div style={{ position: 'absolute', bottom: '40px', right: '40px', textAlign: 'right' }}>
          <p style={{ color: '#888', margin: 0 }}>Peak Concentration</p>
          <h1 style={{ fontSize: '48px', margin: 0, color: data.peak_value > 0.12 ? '#ff2d2d' : '#00d2ff' }}>
            {data.peak_value.toFixed(4)} <span style={{ fontSize: '18px' }}>mg/L</span>
          </h1>
        </div>
      </div>
    </div>
  );
}
